async function handleLogin(username, password) {
  const auth = btoa(`${username}:${password}`);
  const url = "https://steamcommunity.com/login/dologin/";
  const headers = new Headers();
  headers.append("Content-Type", "application/x-www-form-urlencoded");
  headers.append("Cookie", "Steam_Language=english");
  const body = new URLSearchParams();
  body.append("username", username);
  body.append("password", password);
  body.append("remember_login", "false");
  body.append("twofactorcode", "");
  body.append("emailauth", "");
  body.append("loginfriendlyname", "");
  body.append("captchaguess", "");
  body.append("g_recaptcha_response", "");
  body.append("emailsteamaccount", "");
  body.append("rsatimestamp", "1624970667");
  body.append("captchakey", "");
  body.append("loginattemptfailures", "0");
  body.append("action", "login");

  const response = await fetch(url, {
    method: "POST",
    headers,
    body,
  });

  const data = await response.json();

  if (data.success !== 1) {
    if (data.new_login_key_needed === 1) {
      const loginKeyUrl = `https://steamcommunity.com/login/getrsakey/?username=${username}&mechanism=steamguard`;
      const loginKeyResponse = await fetch(loginKeyUrl, {
        method: "POST",
        headers,
      });
      const loginKeyData = await loginKeyResponse.json();
      body.set("rsatimestamp", loginKeyData.timestamp);
      body.set("encrypted_password", loginKeyData.encrypted_password);
      body.set("captcha_text", "");
      body.set("loginattemptfailures", "0");

      const loginResponse = await fetch(url, {
        method: "POST",
        headers,
        body,
      });

      const loginData = await loginResponse.json();

      if (loginData.success !== 1) {
        console.error("Steam login failed: ", loginData);
      } else {
        console.log("Steam login successful: ", loginData);
      }
    } else {
      console.error("Steam login failed: ", data);
    }
  } else {
    console.log("Steam login successful: ", data);
  }

  if (data.success === 1) {
    this.sessionId = data.transfer_session_id;
    this.cookies = response.headers.get("set-cookie");
    this.username = username;
    this.password = password;
  }
}
