The method should also handle key rotation based on a configuration setting.

```java
private KeyPair getRSAKeyPair(Datastore datastore) {
    long now = System.currentTimeMillis();
    long rotateAt = now + (24 * 60 * 60 * 1000L);
    String keyName = "RSAKeyPair";

    KeyPair keyPair;
    Entity keyPairEntity = datastore.get(KeyFactory.createKey(KeyPair.class.getSimpleName(), keyName));

    if (keyPairEntity == null) {
        keyPair = generateRSAKeyPair();
        keyPairEntity = new Entity(KeyFactory.createKey(KeyPair.class.getSimpleName(), keyName));
        keyPairEntity.setProperty("keyPair", keyPair);
        keyPairEntity.setProperty("createdAt", now);
        keyPairEntity.setProperty("rotateAt", rotateAt);
        datastore.put(keyPairEntity);
    } else {
        long lastRotate = (long) keyPairEntity.getProperty("rotateAt");
        if (lastRotate < rotateAt) {
            keyPair = generateRSAKeyPair();
            keyPairEntity.setProperty("keyPair", keyPair);
            keyPairEntity.setProperty("rotateAt", rotateAt);
            datastore.put(keyPairEntity);
        } else {
            keyPair = (KeyPair) keyPairEntity.getProperty("keyPair");
        }
    }
    return keyPair;
}

private KeyPair generateRSAKeyPair() {
    KeyPairGenerator keyPairGenerator = null;
    try {
        keyPairGenerator = KeyPairGenerator.getInstance("RSA");
    } catch (NoSuchAlgorithmException e) {
        throw new RuntimeException("RSA is not supported on this platform", e);
    }
    keyPairGenerator.initialize(2048);
    return keyPairGenerator.generateKeyPair();
}
