private void showErrorPage(HttpServletRequest request, HttpServletResponse response) {
    Throwable throwable = (Throwable) request.getAttribute("javax.servlet.error.exception");
    Integer statusCode = (Integer) request.getAttribute("javax.servlet.error.status_code");
    String servletName = (String) request.getAttribute("javax.servlet.error.servlet_name");

    if (servletName == null) {
        servletName = "Unknown";
    }

    if (statusCode == null) {
        statusCode = 500;
    }

    PrintWriter writer = null;
    try {
        response.setContentType("text/html");
        response.setStatus(statusCode);
        writer = response.getWriter();
        writer.println("<html>");
        writer.println("<head>");
        writer.println("<title>Error Page</title>");
        writer.println("</head>");
        writer.println("<body>");
        writer.println("<h1>Error occurred in servlet: " + servletName + "</h1>");
        writer.println("<h2>Error Code: " + statusCode + "</h2>");
        writer.println("<h2>Throwable Message: " + throwable.getMessage() + "</h2>");
        writer.println("<h2>Stack Trace: </h2>");
        throwable.printStackTrace(writer);
        writer.println("</body>");
        writer.println("</html>");
    } catch (IOException e) {
        e.printStackTrace();
    } finally {
        if (writer != null) {
            writer.close();
        }
    }
}
