Generation:
If a file is not selected, it shows a message "No files selected". Additionally, it handles a button click to remove the last row if it exists. The file input element has a custom class "file-input".

The function should be triggered by a change event on the file input element and by a button click.

HTML:
```html
<input type="file" id="fileInput" class="file-input" multiple />
<button id="removeBtn">Remove last row</button>
<div id="filesList"></div>
```

JavaScript:
```javascript
const fileInput = document.querySelector('#fileInput');
const removeBtn = document.querySelector('#removeBtn');
const filesList = document.querySelector('#filesList');

function handleFileSelection() {
  filesList.innerHTML = '';

  if (fileInput.files.length === 0) {
    filesList.innerHTML = '<p>No files selected</p>';
    return;
  }

  for (const file of fileInput.files) {
    const fileRow = document.createElement('div');
    fileRow.classList.add('file-row');

    const fileIcon = document.createElement('div');
    fileIcon.classList.add('file-icon');
    fileIcon.style.backgroundImage = getFileTypeIcon(file.type);
    fileRow.appendChild(fileIcon);

    const fileName = document.createElement('span');
    fileName.textContent = file.name;
    fileRow.appendChild(fileName);

    const fileSize = document.createElement('span');
    fileSize.textContent = file.size + ' bytes';
    fileRow.appendChild(fileSize);

    filesList.appendChild(fileRow);
  }
}

function getFileTypeIcon(fileType) {
  switch (fileType) {
    case 'image/jpeg':
    case 'image/png':
      return 'url(img/file-icons/image.png)';
    case 'application/pdf':
      return 'url(img/file-icons/pdf.png)';
    case 'application/msword':
    case 'application/vnd.openxmlformats-officedocument.wordprocessingml.document':
      return 'url(img/file-icons/word.png)';
    default:
      return 'url(img/file-icons/other.png)';
  }
}

fileInput.addEventListener('change', handleFileSelection);
removeBtn.addEventListener('click', () => {
  const lastRow = filesList.lastElementChild;
  if (lastRow) {
    filesList.removeChild(lastRow);
  }
});
```

