When a checkbox is clicked, it updates a hidden input field with the new order of columns and displays a visual representation of the new order using a column icon. Additionally, it updates the column icon's title to reflect the new order.

When all checkboxes are deselected, it resets the table to its original state by calling a reset function.

The code should also ensure that the checkbox click event is not triggered when clicking on a label element within the table headers.

```
<script type="text/javascript">
$(document).ready(function() {
    // Handle click events on the checkbox input elements
    $("input[type='checkbox']").click(function(e) {
        if (e.target.nodeName === 'LABEL') {
            return;
        }
        var $input = $(this);
        var $table = $input.closest("table");
        var $tbody = $table.find("tbody");
        var $tr = $tbody.find("tr");
        var $trHeader = $table.find("thead tr");
        var $th = $trHeader.find("th");
        var $icon = $input.closest("td").find(".columnIcon");
        var $iconHeader = $trHeader.find(".columnIcon");
        var $hidden = $table.find("input[name='newOrder']");
        var $inputHeader = $table.find("input[name='newOrderHeader']");
        var $select = $table.find("select[name='moveColumn']");
        var $selectHeader = $table.find("select[name='moveColumnHeader']");
        var $thMove = $tr.find("th.move");
        var $iconMove = $thMove.find(".columnIcon");

        // Reset the table if all checkboxes are deselected
        if ($inputHeader.is(':checked')) {
            $select.val('');
            $selectHeader.val('');
            reset($table, $tbody, $tr, $trHeader, $th, $icon, $iconHeader, $iconMove, $hidden, $inputHeader);
            return;
        }

        // Process the checkbox click event
        var selected = $tbody.find("input[type='checkbox']:checked");
        var selectedCount = selected.length;
        var order = [];
        var orderHeader = [];
        var orderIcon = [];
        var orderIconHeader = [];
        var orderIconMove = [];

        selected.each(function() {
            var index = $tbody.find("input[type='checkbox']").index(this);
            order.push(index);
            orderIcon.push($tbody.find("input[type='checkbox']:checked").eq(index).closest("td").find(".columnIcon").attr("class"));
            orderHeader.push($trHeader.find("input[type='checkbox']:checked").eq(index).closest("td").find(".columnIcon").attr("class"));
            orderIconMove.push($tr.find("th.move input[type='checkbox']:checked").eq(index).closest("td").find(".columnIcon").attr("class"));
        });

        var newOrder = order.join(",");
        var newOrderHeader = orderHeader.join(",");
        var newOrderIcon = orderIcon.join(",");
        var newOrderIconHeader = orderIconHeader.join(",");
        var newOrderIconMove = orderIconMove.join(",");

        $hidden.val(newOrder);
        $inputHeader.val(newOrderHeader);
        $select.val(newOrderIcon);
        $selectHeader.val(newOrderIconHeader);

        $iconMove.attr("class", newOrderIconMove);
        $iconMove.attr("title", newOrderIconMove);

        if (selectedCount === 1) {
            $icon.attr("class", newOrderIcon);
            $icon.attr("title", newOrderIcon);
            $iconHeader.attr("class", newOrderIconHeader);
            $iconHeader.attr("title", newOrderIconHeader);
        }
    });
});
</script>
