The modal has an "Update" button that triggers these updates.

```javascript
$('#modalUpdateButton').click(function() {
    var modal = $('#modal');
    var modalText = modal.find('.modal-body p');
    var modalInput = modal.find('.modal-body input');
    var modalSelect = modal.find('.modal-body select');
    var modalInverted = modal.find('.modal-body input[name="inverted"]');
    var modalCheckbox = modal.find('.modal-body input[name="checkbox"]');
    var modalCheckboxInverted = modalCheckbox.prop('checked') && modalInverted.prop('checked');

    modalText.text('Updating...');
    modalInput.prop('disabled', true);
    modalSelect.prop('disabled', true);
    modalCheckbox.prop('disabled', true);
    modalInverted.prop('disabled', true);

    setTimeout(function() {
        modalInput.prop('disabled', false);
        modalSelect.prop('disabled', false);
        modalCheckbox.prop('disabled', false);
        modalInverted.prop('disabled', false);
        modalText.text('Updated!');

        if (modalCheckboxInverted) {
            modalInput.val('');
            modalSelect.val('');
            modalCheckbox.prop('checked', false);
            modalInverted.prop('checked', false);
        } else {
            modalInput.val('new value');
            modalSelect.val('new option');
            modalCheckbox.prop('checked', true);
            modalInverted.prop('checked', true);
        }
    }, 1000);
});
```
