(function($) {
    $.fn.badgetoggle = function(options) {
        var settings = $.extend({
            style: 'overlay'
        }, options);

        var $this = $(this);

        $this.on('click', function() {
            var badge = $('<span class="badge">badge text</span>');

            if (settings.style === 'overlay') {
                $this.append(badge);
            } else {
                $this.before(badge);
            }

            $this.trigger('badgetoggle', [badge]);
        });
    };
})(jQuery);
