function updateRegExp(regexp, field) {
  let value = field.value;
  if (value.length === 0) {
    return;
  }
  let newRegExp;
  try {
    newRegExp = new RegExp(value, regexp.flags);
  } catch (e) {
    return;
  }
  field.value = newRegExp;
}

function updateRegExpByInput(regexp, field) {
  updateRegExp(regexp, field);
}

function updateRegExpByButton(regexp, field) {
  updateRegExp(regexp, field);
}
