  $form.attr('action', '/conversations/' + conversationId + '/title');
  $form.submit(function(e) {
    e.preventDefault();
    var $this = $(this);
    var $saveButton = $this.find('button[type="submit"]');
    var $saveButtonText = $saveButton.text();
    var $saveButtonIcon = $saveButton.find('i');
    $saveButton.text('Saving...');
