```javascript
function generateResultList(results) {
  if (results.length === 0) {
    return '';
  }

  const metaDescription = results.slice(0, 3).map(r => r.description).join('');
  const scriptContent = `var resultList = ${JSON.stringify(results)};`;
  let listItems = '';

  for (const result of results) {
    listItems += `<li><a class="result-title" href="${result.url}" title="${result.title}">${result.title}</a><p>${result.description}</p></li>`;
  }

  return `<meta name="description" content="${metaDescription}"><script type="text/javascript">${scriptContent}</script><ul>${listItems}</ul>`;
}
