  const { spawnSync } = require('child_process');
  const fs = require('fs');

  if (!outputFile) {
    const { status, error, stdout, stderr } = spawnSync(command, args, { stdio: 'inherit' });
    return { status, error, stdout, stderr };
  }

  const options = { stdio: 'pipe' };
  if (inputFile) {
    options.input = fs.readFileSync(inputFile);
  }
  const { status, error, stdout, stderr } = spawnSync(command, args, options);
  if (!error) {
    fs.writeFileSync(outputFile, stdout);
  }

  return { status, error, stdout, stderr };
}
