    # Create or update git directory
    if not os.path.exists(git_dir):
        subprocess.check_call(['git', 'init'], cwd=git_dir)
    else:
        subprocess.check_call(['git', 'pull'], cwd=git_dir)

    # Perform file operations based on input
    for op in file_ops:
        if op['type'] == 'add':
            with open(os.path.join(git_dir, op['file']), 'w') as f:
                f.write(op['content'])
        elif op['type'] == 'chmod':
            os.chmod(os.path.join(git_dir, op['file']), op['mode'])
        elif op['type'] == 'rm':
            os.remove(os.path.join(git_dir, op['file']))

    # Commit changes
