def read_config(self):
    """Populate the instance with settings for the config file.

    If we can't find any section for the given site, error gracefully.

    """
    defaults = {
        "auth_type": "basic",
        "verify_ssl_cert": "true",
    }

    cp = configparser.RawConfigParser(defaults)
    try:
        cp.read(self.config_file)
    except configparser.ParsingError as e:
        raise ConfigError(e)

    if not cp.has_section(self.site):
        raise ConfigError(f"No section for {self.site} in {self.config_file}")

    for key, value in defaults.items():
        if not cp.has_option(self.site, key):
            raise ConfigError(f"No {key} in {self.site} section of {self.config_file}")

    for key, value in defaults.items():
        setattr(self, key, cp.get(self.site, key))

