The component should accept the following props:
- `repoPath`: The path to the repository.
- `match`: The match string to search for.
- `matches`: An array of matched lines.
- `lineNumbers`: An array of line numbers corresponding to the matched lines.

The component should render a list of matched lines, with each line containing the following elements:
- A link to the source code, using the `repoPath`, `file`, and `line` props.
- A `<span>` element containing the matched line, with the matched text highlighted in bold.

The component should also render a "Matched files" section, listing the files that contain matches. Each file should be a link to the corresponding file in the repository.

Here is an example of the rendered output:
```
Matched lines:
1: <a href="https://github.com/user/repo/blob/master/file1.js#L1">file1.js</a> - <span><b>matched</b> text</span>
2: <a href="https://github.com/user/repo/blob/master/file2.js#L2">file2.js</a> - <span>matched text</span>

Matched files:
1: <a href="https://github.com/user/repo/blob/master/file1.js">file1.js</a>
2: <a href="https://github.com/user/repo/blob/master/file2.js">file2.js</a>
```

Note: The `repoPath`, `file`, and `line` props should be passed to the `<a>` tags to create the appropriate links.

```jsx
import React from 'react';

export default class SearchResults extends React.Component {
  render() {
    const { repoPath, match, matches, lineNumbers } = this.props;
    const lines = [];
    const files = new Set();

    for (let i = 0; i < matches.length; i++) {
      const match = matches[i];
      const file = lineNumbers[i];
      const lines = match.split('\n');

      files.add(file);
      lines.forEach((line, j) => {
        lines[j] = (
          <span key={j}>
            {line.split(match).map((part, k) => k ? <b key={k}>{part}</b> : part)}
          </span>
        );
      });

      lines.push(<a key="file" href={`https://github.com/user/repo/blob/master/${file}`}>{file}</a>);
      lines.push(<a key="line" href={`https://github.com/user/repo/blob/master/${file}#L${i + 1}`}>L{i + 1}</a>);
      lines.push(<br key="br" />);
    }

    return (
      <div>
        <h3>Matched lines:</h3>
        {lines}
        <h3>Matched files:</h3>
        {Array.from(files).map((file) => (
          <a href={`https://github.com/user/repo/blob/master/${file}`}>{file}</a>
        ))}
      </div>
    );
  }
}
