class QuestionList extends React.Component {
  constructor(props) {
    super(props);
    this.state = { answersVisible: false };
  }

  toggleAnswers = () => {
    this.setState({ answersVisible: !this.state.answersVisible });
  };

  render() {
    const { questions } = this.props;
    const { answersVisible } = this.state;

    return (
      <div>
        <button onClick={this.toggleAnswers}>
          {answersVisible ? 'Hide Answers' : 'Show Answers'}
        </button>
        <ul style={{ listStyle: 'none', padding: 0, margin: 0 }}>
          {questions.map((question, index) => (
            <li key={index} style={{ borderBottom: '1px solid #ddd', padding: '10px 0' }}>
              {question.avatar ? (
                <img
                  src={question.avatar}
                  alt="avatar"
                  style={{ width: '50px', height: '50px', borderRadius: '50%', marginRight: '10px' }}
                />
              ) : null}
              <p>{question.question}</p>
              {answersVisible && <p>{question.answer}</p>}
              {question.link ? (
                <a href={question.link} target="_blank" rel="noopener noreferrer">
                  {question.link}
                </a>
              ) : null}
            </li>
          ))}
        </ul>
      </div>
    );
  }
}
