func tally(w http.ResponseWriter, r *http.Request) {
    n, err := strconv.Atoi(r.URL.Query().Get("n"))
    if err != nil || n < 1 || n > 30 {
        http.Error(w, "Invalid tally count", http.StatusBadRequest)
        return
    }
    rows, err := db.Query("SELECT date, tally FROM dailytally ORDER BY id DESC LIMIT ?", n)
    if err != nil {
        log.Println(err)
        http.Error(w, "Database error", http.StatusInternalServerError)
        return
    }
    defer rows.Close()
    var t []tally
    for rows.Next() {
        var row tally
        if err := rows.Scan(&row.Date, &row.Tally); err != nil {
            log.Println(err)
            http.Error(w, "Database error", http.StatusInternalServerError)
            return
        }
        t = append(t, row)
    }
    if err := rows.Err(); err != nil {
        log.Println(err)
        http.Error(w, "Database error", http.StatusInternalServerError)
        return
    }
    w.Header().Set("Content-Type", "application/json")
    json.NewEncoder(w).Encode(t)
}
