func (h *Handler) DisplayTable(w http.ResponseWriter, r *http.Request) {
	t := r.URL.Query().Get("t")
	if t == "" {
		http.Error(w, "No table specified", http.StatusBadRequest)
		return
	}
	var rows [][]string
	err := h.db.Select(&rows, "SELECT * FROM "+t)
	if err != nil {
		log.Printf("Error executing query: %v", err)
		http.Error(w, "Error displaying table", http.StatusInternalServerError)
		return
	}
	err = Template.Execute(w, struct {
		Table string
		Rows  [][]string
	}{
		Table: t,
		Rows:  rows,
	})
	if err != nil {
		log.Printf("Error executing template: %v", err)
		http.Error(w, "Error displaying table", http.StatusInternalServerError)
		return
	}
}
