    return note.slice(0, operation.start) + operation.character + note.slice(operation.start);
  } else if (operation.operation.toLowerCase() === 'delete') {
    if (operation.start > operation.end || operation.start > note.length) return note;
    return note.slice(0, operation.start) + note.slice(operation.end);
  }
}
