def _create_database(engine: "Engine", db: Text):
    """Create database `db` on `engine` if it does not exist."""

    import psycopg2

    conn = engine.connect()

    cursor = conn.connection.cursor()
    cursor.execute("COMMIT")
    cursor.execute(
