private void updateModule(String moduleIdentifier, List<String> moduleFiles, boolean dryRun) throws IOException {
    String moduleLocation = getModuleLocation(moduleIdentifier);
    String tempModuleLocation = moduleLocation + ".tmp";
    String archiveFile = getArchiveFile(moduleIdentifier);

