        logger.info("Extracting " + archiveFile + " to " + tempModuleLocation);
        extractFiles(archiveFile, tempModuleLocation);

        logger.info("Replacing " + moduleFiles + " in " + moduleLocation);
        replaceFiles(moduleFiles, moduleLocation, tempModuleLocation);
    }

    logger.info("Updating " + moduleIdentifier);
    String currentVersion = moduleProperties.getProperty(moduleIdentifier + ".version");
    String newVersion = getModuleVersion(moduleIdentifier, archiveFile);
    moduleProperties.setProperty(moduleIdentifier + ".version", newVersion);

    if (!dryRun) {
        logger.info("Deleting " + moduleLocation);
        delete(moduleLocation);

        logger.info("Renaming " + tempModuleLocation + " to " + moduleLocation);
        rename(tempModuleLocation, moduleLocation);

        logger.info("Deleting " + archiveFile);
        delete(archiveFile);

        logger.info("Updating " + modulePropertiesFile);
        updateProperties(modulePropertiesFile, moduleIdentifier, currentVersion, newVersion);
