private void downloadArchive(String moduleIdentifier, String archiveFile) throws IOException {
    URL url = new URL(moduleProperties.getProperty(moduleIdentifier + ".archive"));
    try (InputStream in = url.openStream();
         FileOutputStream out = new FileOutputStream(archiveFile)) {
        byte[] buffer = new byte[8192];
        int bytesRead;
        while ((bytesRead = in.read(buffer)) != -1) {
            out.write(buffer, 0, bytesRead);
        }
    }
}

private void extractFiles(String archiveFile, String tempModuleLocation) throws IOException {
    try (ZipInputStream zip = new ZipInputStream(new FileInputStream(archiveFile))) {
        ZipEntry entry;
        while ((entry = zip.getNextEntry()) != null) {
            String name = entry.getName();
            File file = new File(tempModuleLocation, name);
            if (entry.isDirectory()) {
                file.mkdirs();
            } else {
                file.getParentFile().mkdirs();
                try (FileOutputStream out = new FileOutputStream(file)) {
                    byte[] buffer = new byte[8192];
                    int bytesRead;
                    while ((bytesRead = zip.read(buffer)) != -1) {
                        out.write(buffer, 0, bytesRead);
                    }
                }
            }
            zip.closeEntry();
        }
    }
}

private void replaceFiles(List<String> moduleFiles, String moduleLocation, String tempModuleLocation) throws IOException {
    for (String moduleFile : moduleFiles) {
        File oldFile = new File(moduleLocation, moduleFile);
        File newFile = new File(tempModuleLocation, moduleFile);
        if (oldFile.exists()) {
            if (!dryRun) {
                logger.info("Deleting " + oldFile);
                delete(oldFile);
            }
        }
        if (!dryRun) {
            logger.info("Renaming " + newFile + " to " + oldFile);
            rename(newFile, oldFile);
        }
    }
}
