@bp.route('/browse', methods=['GET', 'POST'])
@login_required
def browse():
    if request.method == 'GET':
        if current_user.is_authenticated:
            jobdir = session.get('jobdir')
            if jobdir is None:
                return redirect(url_for('root'))

            tree = browse_dir(jobdir)

            return render_template('browse.html', tree=tree, jobdir=jobdir)

    if request.method == 'POST':
        if current_user.is_authenticated:
            jobdir = session.get('jobdir')
            if jobdir is None:
                return redirect(url_for('root'))

            jobname = request.form.get('jobname', None)
            filename = request.form.get('filename', None)

            tree = browse_dir(jobdir)

            if jobname:
                jobdir = os.path.join(jobdir, jobname)
                session.update(jobdir=jobdir)

                tree = browse_dir(jobdir)

            return render_template('browse.html', tree=tree, jobdir=jobdir)

    return render_template('browse.html', tree=None, jobdir=None)
