def replace_destination_directory(source, destination, recursive=False):
    """Replace destination directory with source directory, adjusting permissions for webserver access.

    :param source: Directory to copy from.
    :param destination: Directory to copy to.
    :param recursive: If True, copy directories recursively.
    """
    # Check if destination exists and remove it if it does
