def update_dir_from_tar(tar_file, dir_path, extract=False, update=False):
    """
    Update the directory structure from a TAR file.

    :param tar_file: tarfile object
    :param dir_path: str, path to the directory to update
    :param extract: bool, whether to extract files from the tar file
    :param update: bool, whether to update the directory structure
    """
    if not tar_file:
        raise ValueError("tar_file must be a tarfile object")
    if not os.path.isdir(dir_path):
        raise ValueError("dir_path must be a directory")
    if not extract and not update:
        raise ValueError("extract or update must be True")
    tar_dir = tar_file.getmembers()
    tar_dir.sort(key=lambda x: x.name)
    for tar_info in tar_dir:
        tar_path = os.path.join(dir_path, tar_info.name)
        if tar_info.isdir():
            if extract:
                os.makedirs(tar_path, exist_ok=True)
            elif update:
                if not os.path.isdir(tar_path):
                    os.makedirs(tar_path, exist_ok=True)
        elif tar_info.isfile():
            if extract:
                tar_file.extract(tar_info, dir_path)
            elif update:
                if not os.path.isfile(tar_path) or tar_info.size > os.path.getsize(tar_path):
                    tar_file.extract(tar_info, dir_path)
