static inline void cache_local_ip_port(struct connection *c, bool cache_ip)
{
	int err;
	struct sockaddr_storage ss;
	struct sockaddr_in *sin;
	struct sockaddr_in6 *sin6;
	struct sockaddr *sa = (struct sockaddr *)&ss;
	int salen = sizeof(ss);

	err = getsockname(c->sock->fd, sa, &salen);
	if (err)
		return;

	switch (sa->sa_family) {
	case AF_INET:
		sin = (struct sockaddr_in *)sa;
		c->local_ip4 = sin->sin_addr.s_addr;
		if (cache_ip)
			c->local_ip = c->local_ip4;
		c->local_port = ntohs(sin->sin_port);
		break;
	case AF_INET6:
		sin6 = (struct sockaddr_in6 *)sa;
		memcpy(&c->local_ip6, sin6->sin6_addr.s6_addr32,
		       sizeof(c->local_ip6));
		if (cache_ip)
			c->local_ip = c->local_ip6;
		c->local_port = ntohs(sin6->sin6_port);
		break;
	default:
		break;
	}
}
