static int pdf_add_bookmark_rec(pdf_document *doc, pdf_obj *bookmark,
                                 int *pos)
{
	int num;
	pdf_obj *parent;

	num = doc->num_bookmarks;
	doc->num_bookmarks++;

	parent = pdf_new_dict(doc->heap);
	pdf_add_key_value(parent, "Title", pdf_new_string(doc->heap,
	                                                     "TOC", 3));
	pdf_add_key_value(parent, "Parent", pdf_new_indirect(doc->heap, 0, 0));
	pdf_add_key_value(parent, "First", bookmark);
	pdf_add_key_value(parent, "Last", bookmark);
	pdf_add_key_value(parent, "Next", pdf_new_indirect(doc->heap, 0, 0));
	pdf_add_key_value(parent, "Prev", pdf_new_indirect(doc->heap, 0, 0));
	pdf_add_key_value(parent, "Dest", pdf_new_indirect(doc->heap, 0, 0));
	pdf_add_key_value(parent, "Count", pdf_new_number(doc->heap, 0));

	if (pos) {
		*pos = num;
	}
	doc->root_bookmark = pdf_add_bookmark_rec(doc, parent, 0);
