static int bt_mesh_cfg_cli_read(struct bt_mesh_cfg_cli *cfg_cli,
				struct bt_mesh_net_tx *tx,
				struct bt_mesh_msg_ctx *ctx,
				const struct bt_mesh_uuid *uuid,
				struct net_buf_simple *buf)
{
	struct bt_mesh_cfg_status status;
	struct net_buf_simple *msg = &cfg_cli->msg;
	struct bt_mesh_cfg_cli_cb cb;
	int err;

	if (uuid->size > sizeof(msg->data)) {
		return -EINVAL;
	}

	net_buf_simple_reset(buf);
	net_buf_simple_add_u8(buf, BT_MESH_CFG_CLI_READ);
	net_buf_simple_add_u8(buf, uuid->size);
	memcpy(net_buf_simple_add(buf, uuid->size), uuid->data, uuid->size);

	if (bt_mesh_cfg_cli_send(cfg_cli, tx, ctx, buf, &status,
				 sizeof(status), BT_MESH_CFG_CLI_TIMEOUT)) {
		return -EIO;
	}

	if (status.success != BT_MESH_SUCCESS) {
		return -EIO;
	}

	err = bt_mesh_cfg_cli_cb_find(&cfg_cli->cb_list, ctx->addr, uuid,
				      BT_MESH_CFG_CLI_CB_READ, &cb);
	if (err) {
		return err;
	}

	net_buf_simple_reset(msg);
	net_buf_simple_add_u8(msg, BT_MESH_CFG_CLI_READ);
	net_buf_simple_add_u8(msg, uuid->size);
	memcpy(net_buf_simple_add(msg, uuid->size), uuid->data, uuid->size);

	return cb.cfg_cli->cb(cb.cfg_cli, ctx->addr, &status,
			      net_buf_simple_pull(msg, uuid->size + 2),
			      net_buf_simple_tailroom(msg));
}
